import { jsx, jsxs } from 'react/jsx-runtime';
import { classNames } from '../../helpers/classnames.js';
import { useCallback, useEffect } from 'react';
import { Modal } from '../Modal/Modal.js';

const Dialog = ({ open = false, onClose, children, applicationRootElement, className, ...rest }) => {
    const handleEscClick = useCallback((event) => {
        if (event.keyCode === 27 && onClose) {
            onClose(event);
        }
    }, [onClose]);
    useEffect(() => {
        //Добавляем if, так как useCallback будет работать только если передаваемый onClose будет обернут в  useCallback. Иначе это бесполезно
        if (open) {
            document.addEventListener('keydown', handleEscClick, false);
        }
        else {
            document.removeEventListener('keydown', handleEscClick, false);
        }
        return () => {
            document.removeEventListener('keydown', handleEscClick, false);
        };
    }, [handleEscClick, open]);
    return (jsx(Modal, { "data-testid": "Dialog", open: open, className: classNames('dsb_modal', open && 'dsb_modal__open'), applicationRootElement: applicationRootElement, children: jsxs("div", { className: classNames('dsb_dialog', className), children: [jsx("div", { className: "dsb_dialog-backdrop" }), children] }) }));
};

export { Dialog };
